patch:
diff --git a/src/eligibility.mjs b/src/eligibility.mjs
index 09e9242..5e5c21f 100644
--- a/src/eligibility.mjs
+++ b/src/eligibility.mjs
@@ -2,9 +2,10 @@ export function decideScholarship(applicant) {
   const income = Number(applicant.annualHouseholdIncome);
   const age = Number(applicant.age);
   const hasDisability = Boolean(applicant.hasDisability);
-  const eligible = income < 250_000 && age <= 25;
+  const maxAge = hasDisability ? 31 : 27;
+  const eligible = income <= 437500 && age <= maxAge;
   return {
     outcomeCode: eligible ? "ELIGIBLE" : "INELIGIBLE",
-    explanation: `Node production evaluated income ${income} < 250000 and age ${age} <= 25; disability=${hasDisability}.`,
+    explanation: `Node production evaluated income ${income} <= 437500 and age ${age} <= ${maxAge}; disability=${hasDisability}.`,
   };
 }

